# scripts/module_health.py  — weekly health report generator
from dataclasses import dataclass
from datetime import datetime, timedelta
from typing import Optional

@dataclass
class ModuleHealth:
    module: str
    open_prs: int
    oldest_open_pr_days: int
    test_coverage_pct: float
    last_dep_upgrade_days: int
    eval_baseline_age_days: int

    def is_healthy(self) -> bool:
        return (
            self.open_prs < 10
            and self.oldest_open_pr_days <= 5
            and self.test_coverage_pct >= 85.0
            and self.last_dep_upgrade_days <= 45
            and self.eval_baseline_age_days <= 90
        )

    def health_issues(self) -> list[str]:
        issues = []
        if self.open_prs >= 10:
            issues.append(f"{self.open_prs} open PRs (threshold: < 10)")
        if self.oldest_open_pr_days > 5:
            issues.append(f"Oldest PR {self.oldest_open_pr_days}d old (SLA: 3 days)")
        if self.test_coverage_pct < 85.0:
            issues.append(f"Coverage {self.test_coverage_pct:.1f}% (threshold: 85%)")
        if self.last_dep_upgrade_days > 45:
            issues.append(f"Deps not upgraded for {self.last_dep_upgrade_days}d (threshold: 45)")
        if self.eval_baseline_age_days > 90:
            issues.append(f"Eval baseline {self.eval_baseline_age_days}d old (threshold: 90)")
        return issues

